Greedy cost-driven insertion evaluates each ship's feasible placement across all routes by incremental cost increase, commits the minimal increase while preserving time windows and capacity, and falls back to a fresh route if needed.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
    nOrders := len(oris)
    for shipIdx := 0; shipIdx < nOrders; shipIdx++ {
        bestAssignIdx := -1
        var bestCostDelta float64
        firstFeasibleFallbackIdx := -1

        // Try inserting into existing non‑empty routes first
        for assignIdx := 0; assignIdx < dispatch.AssignsLen; assignIdx++ {
            assign := &dispatch.Assigns[assignIdx]

            // Save current cost
            oldCost := assign.Cost

            id := total_ship + shipIdx
            ok := assign.AddShip(id, oris[shipIdx], dess[shipIdx])
            if !ok || assign.Cost < 0 {
                assign.RemoveShip(id)
                assign.GenRoute()
                continue
            }

            assign.GenRoute()
            newCost := assign.Cost
            if newCost >= 0 {
                if firstFeasibleFallbackIdx == -1 {
                    firstFeasibleFallbackIdx = assignIdx
                }
                costDelta := newCost - oldCost
                if bestAssignIdx == -1 || costDelta < bestCostDelta {
                    bestAssignIdx = assignIdx
                    bestCostDelta = costDelta
                }
            }

            // Rollback trial
            assign.RemoveShip(id)
            assign.GenRoute()
        }

        // If found among existing routes, commit the best one
        if bestAssignIdx != -1 {
            assign := &dispatch.Assigns[bestAssignIdx]
            id := total_ship + shipIdx
            assign.AddShip(id, oris[shipIdx], dess[shipIdx])
            assign.GenRoute()
            continue
        }

        // Fallback: try empty slots (including possibly extending AssignsLen)
        placed := false
        // First try truly empty slots up to current length
        for assignIdx := 0; assignIdx < dispatch.AssignsLen; assignIdx++ {
            assign := &dispatch.Assigns[assignIdx]
            if assign.StationsLen > 0 {
                continue
            }
            id := total_ship + shipIdx
            ok := assign.AddShip(id, oris[shipIdx], dess[shipIdx])
            if !ok || assign.Cost < 0 {
                assign.RemoveShip(id)
                assign.GenRoute()
                continue
            }
            assign.GenRoute()
            placed = true
            break
        }
        if placed {
            continue
        }

        // Last resort: create a new route at the end if within bounds
        if dispatch.AssignsLen < MAXASSIGNS {
            assign := &dispatch.Assigns[dispatch.AssignsLen]
            id := total_ship + shipIdx
            ok := assign.AddShip(id, oris[shipIdx], dess[shipIdx])
            if ok && assign.Cost >= 0 {
                assign.GenRoute()
                dispatch.AssignsLen++
                placed = true
            } else {
                assign.RemoveShip(id)
                assign.GenRoute()
            }
        }

        // Safety: if still not placed and we had at least one feasible slot earlier,
        // force‑place into the first feasible slot recorded (seed‑style).
        if !placed && firstFeasibleFallbackIdx != -1 {
            assign := &dispatch.Assigns[firstFeasibleFallbackIdx]
            id := total_ship + shipIdx
            assign.AddShip(id, oris[shipIdx], dess[shipIdx])
            assign.GenRoute()
        }
    }
    dispatch.RenewnTotalCost()
    return dispatch

